import { useState, useCallback, useEffect } from 'react';
import { optimise } from './engineV2';
import { I18N, useLang } from './i18n';
import { supabase, saveProject, loadProject, signOut } from './supabase';
import ProjectForm from './components/ProjectForm';
import PiecesList from './components/PiecesList';
import Results from './components/Results';
import AuthScreen from './components/AuthScreen';
import ProjectsScreen from './components/ProjectsScreen';
// On retire l'import du Header séparé
import { Scissors, ChevronLeft, User, LogOut, Save, Database, Globe, Disc } from 'lucide-react';
import './App.css';

const SCREENS = { AUTH: 'auth', PROJECTS: 'projects', FORM: 'form', PIECES: 'pieces', RESULTS: 'results' };
const DEFAULT_PROJECT = { name: '', client: '', company: '', panel: { w: 244, h: 122 }, kerf: 3, tolerance: 10, pricePerPanel: 39.8, pieces: [], furniture: [], devisNum: '', supabaseId: null };

// Composant Header Interne (pour éviter les problèmes de props)
const InternalHeader = ({ title, subtitle, onBack, user, onLogout, steps, onSave, saving, saveMsg, lang, onToggleLang }) => (
  <header className="sticky top-0 z-50 bg-[#0a0a0a]/95 backdrop-blur-md border-b border-white/5 shadow-xl h-16">
    <div className="max-w-5xl mx-auto px-4 h-full flex items-center justify-between">
      <div className="flex items-center gap-3 flex-1 min-w-0">
        {onBack && (
          <button onClick={onBack} className="p-2 -ml-2 text-slate-400 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
            <ChevronLeft className="w-6 h-6" />
          </button>
        )}
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => !onBack && window.location.reload()}>
          <div className="w-9 h-9 bg-gradient-to-br from-orange-500 to-red-600 rounded-lg flex items-center justify-center shadow-lg shadow-orange-500/20 hover:rotate-45 transition-transform duration-500">
            <Scissors className="w-5 h-5 text-white" />
          </div>
          <div className="hidden sm:block">
            <h1 className="text-base font-bold text-white leading-tight">PanelCut <span className="text-orange-500">Pro</span></h1>
            {subtitle && <p className="text-[10px] text-slate-400 uppercase tracking-wide">{subtitle}</p>}
          </div>
        </div>
      </div>

      {steps && steps.length > 0 && (
        <div className="absolute left-1/2 -translate-x-1/2 hidden md:flex items-center bg-[#111] border border-white/5 rounded-full px-2 py-1">
          {steps.map((step, i) => (
            <div key={i} className="flex items-center">
              <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-[10px] font-bold uppercase transition-all ${step.active ? 'bg-orange-500 text-white shadow-lg shadow-orange-500/30' : 'text-slate-500'}`}>
                <span className={`w-4 h-4 rounded-full flex items-center justify-center text-[9px] ${step.active ? 'bg-white/20' : 'bg-white/5 border border-white/10'}`}>{i+1}</span>
                <span className="hidden lg:inline">{step.label}</span>
              </div>
              {i < steps.length - 1 && <div className={`w-6 h-0.5 mx-1 ${step.active ? 'bg-orange-500/50' : 'bg-white/5'}`} />}
            </div>
          ))}
        </div>
      )}

      <div className="flex items-center gap-2 flex-1 justify-end">
        {(saveMsg || saving) && (
          <div className={`hidden sm:flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-bold ${saveMsg?.includes('✓') ? 'bg-green-500/10 text-green-400' : 'bg-blue-500/10 text-blue-400'}`}>
            {saving ? <Database className="w-3.5 h-3.5 animate-spin" /> : <Save className="w-3.5 h-3.5" />}
            <span>{saving ? '...' : saveMsg}</span>
          </div>
        )}
        {onSave && (
          <button onClick={onSave} disabled={saving} className="group relative flex items-center justify-center w-9 h-9 bg-white/5 hover:bg-green-600 text-slate-300 hover:text-white rounded-lg border border-white/10 hover:border-green-500 transition-all disabled:opacity-50">
            {saving ? <Database className="w-4 h-4 animate-spin" /> : <Disc className="w-4 h-4 group-hover:scale-110 transition-transform" />}
          </button>
        )}
        {onToggleLang && (
          <button onClick={onToggleLang} className="group relative flex items-center justify-center w-9 h-9 bg-white/5 hover:bg-blue-600 text-slate-300 hover:text-white rounded-lg border border-white/10 hover:border-blue-500 transition-all">
            <Globe className="w-4 h-4 group-hover:rotate-12 transition-transform" />
            <span className="absolute text-[9px] font-bold ml-3.5 mt-2.5 pointer-events-none">{lang === 'fr' ? 'EN' : 'FR'}</span>
          </button>
        )}
        {(onSave || onToggleLang || user) && <div className="w-px h-4 bg-white/10 mx-1" />}
        {user ? (
          <div className="flex items-center gap-2 bg-white/5 hover:bg-white/10 border border-white/5 rounded-full pl-1 pr-2 py-1 cursor-pointer transition-colors" onClick={onLogout}>
            <div className="w-6 h-6 bg-gradient-to-tr from-blue-500 to-purple-600 rounded-full flex items-center justify-center text-[10px] font-bold text-white">
              {user.email[0].toUpperCase()}
            </div>
            <span className="text-xs text-slate-300 hidden sm:block mr-1 max-w-[80px] truncate">{user.email.split('@')[0]}</span>
            <LogOut className="w-3.5 h-3.5 text-slate-500 hover:text-red-400" />
          </div>
        ) : (
          <div className="w-8 h-8 bg-white/5 rounded-full flex items-center justify-center border border-white/5">
            <User className="w-4 h-4 text-slate-500" />
          </div>
        )}
      </div>
    </div>
  </header>
);

export default function App() {
  const lang = useLang();
  const [langOverride, setLangOverride] = useState(lang);
  const tr = I18N[langOverride] || I18N['fr'];

  const [screen, setScreen] = useState(SCREENS.AUTH);
  const [user, setUser] = useState(null);
  const [project, setProject] = useState({ ...DEFAULT_PROJECT });
  const [results, setResults] = useState(null);
  const [computing, setComputing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [saveMsg, setSaveMsg] = useState('');

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) { setUser(session.user); setScreen(SCREENS.PROJECTS); }
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) { setUser(session.user); setScreen(SCREENS.PROJECTS); }
      else { setUser(null); setScreen(SCREENS.AUTH); }
    });
    return () => subscription.unsubscribe();
  }, []);

  const startNew = (devisNum = '') => { setProject({ ...DEFAULT_PROJECT, devisNum }); setResults(null); setScreen(SCREENS.FORM); };

  const goBack = () => {
    if (screen === SCREENS.RESULTS) setScreen(SCREENS.PIECES);
    else if (screen === SCREENS.PIECES) setScreen(SCREENS.FORM);
    else if (screen === SCREENS.FORM) setScreen(user ? SCREENS.PROJECTS : SCREENS.AUTH);
    else setScreen(SCREENS.AUTH);
  };

  const handleLoadProject = async (id) => {
    const { data, error } = await loadProject(id);
    if (error || !data) return;
    const p = { ...data.project_data, supabaseId: data.id };
    setProject(p);
    if (data.results_data) { setResults(data.results_data); setScreen(SCREENS.RESULTS); }
    else setScreen(SCREENS.PIECES);
  };

  const handleOptimize = useCallback(() => {
    if (!project.pieces.length) return;
    setComputing(true);
    setTimeout(async () => {
      const res = optimise(project.pieces, project.panel, { kerf: project.kerf, tolerance: project.tolerance });
      setResults(res); setComputing(false); setScreen(SCREENS.RESULTS);
      if (user) {
        setSaving(true);
        const { data, error } = await saveProject(project, res);
        setSaving(false);
        if (!error && data) { setProject(p => ({ ...p, supabaseId: data.id })); setSaveMsg('✓ Sauvegardé'); setTimeout(() => setSaveMsg(''), 3000); }
      }
    }, 50);
  }, [project, user]);

  const handleSave = async () => {
    if (!user) { alert("Connectez-vous pour sauvegarder"); return; }
    setSaving(true);
    const { data, error } = await saveProject(project, results);
    setSaving(false);
    if (!error && data) { 
      setProject(p => ({ ...p, supabaseId: data.id })); 
      setSaveMsg('✓ Sauvegardé'); 
    } else { 
      setSaveMsg('✗ Erreur'); 
    }
    setTimeout(() => setSaveMsg(''), 3000);
  };

  const handleSignOut = async () => { await signOut(); setUser(null); setScreen(SCREENS.AUTH); };
  const toggleLang = () => setLangOverride(l => l === 'fr' ? 'en' : 'fr');

  const devisNum = 'DV-' + new Date().getFullYear() + '-' + String(Math.floor(Math.random() * 9000) + 1000);
  const showBack = [SCREENS.FORM, SCREENS.PIECES, SCREENS.RESULTS].includes(screen);
  const showSave = user && [SCREENS.PIECES, SCREENS.RESULTS].includes(screen);

  let headerTitle = "PanelCut Pro"; let headerSubtitle = ""; let steps = [];

  if (screen === SCREENS.PROJECTS) { headerTitle = tr.appName; headerSubtitle = user?.email || "Invité"; }
  else if (screen === SCREENS.FORM) { headerTitle = tr.newProject; headerSubtitle = tr.configuration; steps = [{ label: tr.panel, active: true }, { label: tr.pieces, active: false }, { label: tr.results, active: false }]; }
  else if (screen === SCREENS.PIECES) { headerTitle = project.name || tr.newProject; headerSubtitle = tr.piecesToCut; steps = [{ label: tr.panel, active: true }, { label: tr.pieces, active: true }, { label: tr.results, active: false }]; }
  else if (screen === SCREENS.RESULTS) { headerTitle = tr.results; headerSubtitle = tr.optimizedLayout; steps = [{ label: tr.panel, active: true }, { label: tr.pieces, active: true }, { label: tr.results, active: true }]; }

  const hasHeader = screen !== SCREENS.AUTH;

  return (
    <div className="app min-h-screen bg-[#050505] text-slate-200 font-sans selection:bg-orange-500 selection:text-white">
      {hasHeader && (
        <InternalHeader 
          title={headerTitle} 
          subtitle={headerSubtitle} 
          onBack={showBack ? goBack : undefined}
          user={user} 
          onLogout={handleSignOut} 
          steps={steps}
          onSave={showSave ? handleSave : undefined} 
          saving={saving} 
          saveMsg={saveMsg}
          lang={langOverride} 
          onToggleLang={toggleLang}
        />
      )}

      <main className={`w-full max-w-5xl mx-auto px-4 ${hasHeader ? 'mt-24 mb-20' : 'mt-0'}`}>
        {screen === SCREENS.AUTH && <AuthScreen onSkip={() => setScreen(SCREENS.PROJECTS)} />}
        {screen === SCREENS.PROJECTS && <ProjectsScreen user={user} onNew={() => startNew(devisNum)} onLoad={handleLoadProject} />}
        {screen === SCREENS.FORM && <ProjectForm t={tr} project={project} onChange={setProject} onNext={() => setScreen(SCREENS.PIECES)} />}
        {screen === SCREENS.PIECES && <PiecesList t={tr} project={project} onChange={setProject} onOptimize={handleOptimize} computing={computing} />}
        {screen === SCREENS.RESULTS && results && <Results t={tr} results={results} project={project} />}
      </main>
    </div>
  );
}
